class Solution {
    public int coinChange(int[] coins, int amount) {
        return dp(coins, amount, 0);
    }

    private int dp(int[] coins, int amount, int index) {
        if (amount == 0) return 0;
        if (amount < 0 || index == coins.length) return Integer.MAX_VALUE;
        // Use current coin
        int use = dp(coins, amount - coins[index], index);
        if (use != Integer.MAX_VALUE) use += 1;
        // Skip current coin
        int skip = dp(coins, amount, index + 1);
        return Math.min(use, skip);
    }
}

class Solution {
    public int coinChange(int[] coins, int amount) {
        int[][] memo = new int[amount + 1][coins.length];
        for (int[] row : memo) Arrays.fill(row, -1);
        int res = dp(coins, amount, 0, memo);
        return res == Integer.MAX_VALUE ? -1 : res;
    }

    private int dp(int[] coins, int amount, int index, int[][] memo) {
        if (amount == 0) return 0;
        if (amount < 0 || index == coins.length) return Integer.MAX_VALUE;
        if (memo[amount][index] != -1) return memo[amount][index];
        int use = dp(coins, amount - coins[index], index, memo);
        if (use != Integer.MAX_VALUE) use += 1;
        int skip = dp(coins, amount, index + 1, memo);
        return memo[amount][index] = Math.min(use, skip);
    }
}

class Solution {
    public int coinChange(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1);
        dp[0] = 0;
        for (int coin : coins) {
            for (int i = coin; i <= amount; i++) {
                dp[i] = Math.min(dp[i], dp[i - coin] + 1);
            }
        }
        return dp[amount] > amount ? -1 : dp[amount];
    }
}
